import React from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { CashVoucherList } from '../../../components/kt/CashVoucherList';

/** List toolbar: `formPermissions` via `useVoucherListActions` in `CashVoucherList`. */
const PhieuChiListPage: React.FC = () => {
  const location = useLocation();
  if (new URLSearchParams(location.search).get('paymentMedium')?.toLowerCase() === 'bank') {
    return <Navigate to="/kt/unc" replace />;
  }
  return <CashVoucherList kind="payment" />;
};

export default PhieuChiListPage;
